// @resource     REMOTE_CSS https://drive.corp.amazon.com/view/TOM%20Utilities/TamperMonkey/YMS%20Design%20Changes/newstyle.css?ver=1.5
// @resource     LIGHT_CSS https://drive.corp.amazon.com/view/TOM%20Utilities/TamperMonkey/YMS%20Design%20Changes/newstyle.css?ver=1.5
// @resource     DARK_CSS https://drive.corp.amazon.com/view/TOM%20Utilities/TamperMonkey/YMS%20Design%20Changes/newstyle.dark.css?ver=1.5
// @grant        GM_getResourceText
// @grant        GM_addStyle
// @require      https://code.jquery.com/jquery-3.7.0.min.js
// @run-at       document-end
// ==/UserScript==

/* globals $ */

(function (window, document) {
  window.onload = init;

  GM_addStyle(GM_getResourceText("REMOTE_CSS"));

  // Dodanie stylów FUI dla przycisku kopiowania
  GM_addStyle(`


    .oxy-copy-btn {
      background: transparent;
      color: #f36c00;
      border: 1px solid #333;
      border-radius: 0 !important;
      font-family: 'JetBrains Mono', 'Roboto Mono', monospace;
      font-size: 10px;
      text-transform: uppercase;
      cursor: pointer;
      user-select: none;
      transition: all 0.3s ease-in-out;
      height: 20px;

      &:hover {
          background: #f36c00;
          color: #FFFFFF;
      }

      &:active {
          opacity: 0.8;
      }
    }

  #trailerdashboard .empty,
  #trailerdashboard .emptyalert {
      display: inline-block;
      min-width: 1.5em;
  }

  #trailerdashboard .emptyalert {
      color: #c00;
      font-weight: bold;
  }

      .vehicleIdGroup-LP {
      display: flex;
      align-items: center;
    }


  .shipclerk-bold-label {
      font-size: 12px;
      display: flex;
      align-items: center;
  }

  .shipclerk-seals {
      color: #f36c00 !important;
      display: flex;
      justify-content: left;
      align-items: center;
      height: 30px !important;
      width: 10rem;
      transition: all 0.2s;
      z-index: 99;
      font-size: 1rem;
      background: transparent;
      padding-left: 0.5rem;

  }

  .shipclerk-seals:hover {
      background: #000;
      transform: scale(3);
      color: #FFFFFF !important;
  }

  .vehicle-number-LP {
      color: rgb(0, 72, 188);
      transition: all 0.15s;
      padding: 0.1rem 0.2rem;
      height: 20px;
  }

  .vehicle-number-LP:hover {
      background: var(--bg);
      color: rgb(50, 188, 0);
      transform: scale(4) translateX(0px);
      background: #000;
  }




    `);

  function init() {
    "use strict";
    document.getElementById("mainContainer").insertAdjacentHTML(
      "beforebegin",
      `
                <div id="custom-options-container">
                    <h3 id="dark-mode-label">
                        <t>Dark Mode:</t>
                    </h3>
                    <div id="dark-mode-switch">
                        <input id="dark-mode-toggle" type="checkbox">
                        <label for="dark-mode-toggle"></label>
                    </div>
                    <h3 id="filterTrailer-label">
                        <t>Tagged Trailers:</t>
                    </h3>
                    <div>
                        <input id="filterTrailer-toggle" type="checkbox">
                        <label for="filterTrailer"></label>
                    </div>
                </div>
          `,
    );
    document
      .getElementById("dark-mode-toggle")
      .addEventListener("change", function () {
        // We're going to play the day time, night time game
        if (document.getElementById("dark-mode-toggle").checked) {
          // Night time
          GM_addStyle(GM_getResourceText("DARK_CSS"));
        } else {
          // Day time
          GM_addStyle(GM_getResourceText("LIGHT_CSS"));
        }
      });
    document
      .getElementById("filterTrailer-toggle")
      .addEventListener("change", function () {
        // We're going to do an action once the checkbox for tagged trailers is checked
        if (document.getElementById("filterTrailer-toggle").checked) {
          $("#ship-clerk-dashboard-table tbody tr").show();

          // Keeping the old way in just in case tech team changes the way red/yellow tagged trailers are displayed - var targChecked = ".masterYardLP td:nth-child(7):not('.col8.yardAsset-unavailable')";
          // Looking for specific classes that are displaying the red and yellow tag on YMS and only in the div containing flex-container and row, using this as a filter
          var targChecked = $(".flex-container.row").filter(function () {
            return (
              $(this).children(".yard-asset-yellow,.yard-asset-red").length == 0
            );
          });
          var targCheckedEmpty = $(
            ".masterYardLP td:nth-child(2):not('[class^=col2]')",
          );
          // Combining the above two elements so that we essentially have 2 filters - this is for when the checkbox is CHECKED
          var targCheckedCombined = targChecked.add(targCheckedEmpty);

          // Using our filters above to hide table rows, but ignoring tables that are children
          $(targCheckedCombined).closest("tr").not("tr tr").hide();
        } else {
          // We're going to do the UNDO actions once the checkbox for tagged trailers is UNCHECKED
          $("#ship-clerk-dashboard-table tbody tr").show();

          // Keeping the old way in just in case tech team changes the way red/yellow tagged trailers are displayed - var targUnchecked = ".masterYardLP td:nth-child(7):not('.col8.yardAsset-unavailable')";
          var targUnchecked = $(".flex-container.row").filter(function () {
            return (
              $(this).children(".yard-asset-yellow,.yard-asset-red").length == 0
            );
          });
          var targUncheckedEmpty = $(
            ".masterYardLP td:nth-child(2):not('[class^=col2]')",
          );
          // Combining the above two elements so that we essentially have 2 filters - this is for when the checkbox is UNCHECKED
          var targUncheckedCombined = targUnchecked.add(targUncheckedEmpty);

          // Using our filters above to show table rows again, but ignoring tables that are children
          $(targUncheckedCombined).closest("tr").not("tr tr").show();
        }
      });

    if (window.location.href.indexOf("shipclerk/#/yard") > -1) {
      document.styleSheets[0].insertRule(
        ".note-present-icon {flex-shrink: 0;}",
      );
      document.getElementById("mainContainer").insertAdjacentHTML(
        "beforebegin",
        `
               <div id="trailerdashboard">
                       <h2 style="text-align: center;"><div id="emptyazng">AZNG Empties in PS: <span id="val-emptyazng" class="empty">0</span></div></h2>
                       <h2 style="text-align: center;"><div id="dockempty">AZNG Empties on DD: <span id="val-dockempty" class="empty">0</span></div></h2>
                       <h2 style="text-align: center;"><div id="taggedazng">Tagged AZNG Trailers: <span id="val-taggedazng" class="empty">0</span></div></h2>
                       <h2 style="text-align: center;"><div id="loadedAZNG">Loaded AZNG w/ No VRID: <span id="val-loadedazng" class="empty">0</span></div></h2>
                       <h2 style="text-align: center;"><div id="ddemptydiv">Open Dock Doors: <span id="val-ddempty" class="empty">0</span></div></h2>
                       <h2 style="text-align: center;"><div id="tdrout">Doors TDR'd Out: <span id="val-tdrout" class="empty">0</span></div></h2>
                       <h2 style="text-align: center;"><div id="psemptydiv">Open Slips: <span id="val-psempty" class="empty">0</span></div></h2>
                       <h2 style="text-align: center;"><div id="nonazng">OnSite Non AZNG Emptys: <span id="val-nonazng" class="empty">0</span></div></h2>
                       <h2 style="text-align: center;"><div id="tractors">Tractors: <span id="val-tractors" class="empty">0</span></div></h2>
                       <h2 style="text-align: center;"><div id="nicarts">NICART Loads: <span id="val-nicarts" class="empty">0</span></div></h2>
                       <h2 style="text-align: center;"><div id="wro5bcn4div">WRO5 -> BCN4: <span id="val-wro5bcn4" class="empty">0</span></div></h2>
                   </div>
          `,
      );
      function emptyAZNG() {
        var tagged = 0;
        var nicarts = 0;
        var nonazng = 0;
        var nonoff = 0;
        var tractorsYard = $(".yard-asset-icon-TRACTOR").length;
        var noTDR = $(".NoTDR").length;
        var psEmpty = $(
          "tr.empty-location > td.col1 > div.location-type-ParkingLocation",
        ).length;
        var ddEmpty = $(
          "tr.empty-location > td.col1 > div.location-type-ProcessingLocation",
        ).length;
        var emptyAZNGinPS = 0;
        var emptyAZNGinDD = 0;
        var empty3PinPS = 0;
        var loadedAZNGnoVRID = 0;

        // Zliczanie specyficznych ładunków WRO5 -> BCN4
        var wro5bcn4Count = $("span[title='WRO5->BCN4']").length;

        $("tr.ng-scope").each(function () {
          if (
            $(this).find(".location-type-ParkingLocation").length > 0 &&
            $(this).find(".yardasset-empty").length > 0 &&
            $(this).find('.ownerOperatorCodeGroup :contains("AZNG")').length > 0
          ) {
            emptyAZNGinPS = emptyAZNGinPS + 1;
          }
          if (
            $(this).find(".location-type-ProcessingLocation").length > 0 &&
            $(this).find(".yardasset-empty").length > 0 &&
            $(this).find('.ownerOperatorCodeGroup :contains("AZNG")').length > 0
          ) {
            emptyAZNGinDD = emptyAZNGinDD + 1;
          }
          if (
            $(this).find(".location-type-ParkingLocation").length > 0 &&
            $(this).find(".yardasset-empty").length > 0 &&
            $(this).find('.ownerOperatorCodeGroup :not(:contains("AZNG"))')
              .length > 0
          ) {
            empty3PinPS = empty3PinPS + 1;
          }
        });
        $("tr.ng-scope").each(function () {
          if (
            $(this).find(".yardAsset-unavailable").length > 0 &&
            $(this).find('.ownerOperatorCodeGroup :contains("AZNG")').length > 0
          ) {
            tagged = tagged + 1;
          }
        });
        var wholerows = document.querySelectorAll("tr.ng-scope");
        Array.prototype.forEach.call(wholerows, function (col) {
          if (
            col.innerHTML.match(/highlight yardasset-full"/) &&
            col.innerHTML.match(/AZNG/) &&
            !col.innerHTML.match(/vrid/)
          ) {
            loadedAZNGnoVRID = loadedAZNGnoVRID + 1;
          } else if (
            col.innerHTML.match(/highlight yardasset-empty"/) &&
            !col.innerHTML.match(/TRACTOR highlight yardasset-empty"/) &&
            !col.innerHTML.match(/AZNG/) &&
            !col.innerHTML.match(/vrid/)
          ) {
            nonazng = nonazng + 1;
          } else if (
            col.innerHTML.match(/highlight yardasset-empty"/) &&
            !col.innerHTML.match(/AZNG/) &&
            !col.innerHTML.match(/vrid/) &&
            !col.innerHTML.match(/LDLB/) &&
            !col.innerHTML.match(/BSPC/) &&
            !col.innerHTML.match(/BRDZ/) &&
            !col.innerHTML.match(/DUMMY/) &&
            (!col.innerHTML.match(/class="col1 /) || col.innerHTML.match(/OSY/))
          ) {
            nonoff = nonoff + 1;
          }
          if (
            (col.innerHTML.match(/TransfersEmptyCar/) ||
              col.innerHTML.match(/NICARTS/i)) &&
            !col.innerHTML.match(/yard-asset-icon-TRACTOR/)
          ) {
            nicarts = nicarts + 1;
          }
        });
        var tagtag = "empty";
        var tag = "empty";
        if (psEmpty < 5) {
          tag = "emptyalert";
        } else {
          tag = "empty";
        }
        if (tagged > 2) {
          tagtag = "emptyalert";
        } else {
          tagtag = "empty";
        }
        var my_div = document.getElementById("emptyazng");
        my_div.innerHTML =
          'AZNG Empties in PS: <span id="val-emptyazng" class="' +
          tag +
