                    <h2 style="text-align: center;"><div id="dockempty">AZNG Empties on DD: <span id="val-dockempty" class="empty">0</span></div></h2>
                    <h2 style="text-align: center;"><div id="taggedazng">Tagged AZNG Trailers: <span id="val-taggedazng" class="empty">0</span></div></h2>
                    <h2 style="text-align: center;"><div id="loadedAZNG">Loaded AZNG w/ No VRID: <span id="val-loadedazng" class="empty">0</span></div></h2>
                    <h2 style="text-align: center;"><div id="ddemptydiv">Open Dock Doors: <span id="val-ddempty" class="empty">0</span></div></h2>
                    <h2 style="text-align: center;"><div id="tdrout">Doors TDR'd Out: <span id="val-tdrout" class="empty">0</span></div></h2>
                    <h2 style="text-align: center;"><div id="psemptydiv">Open Slips: <span id="val-psempty" class="empty">0</span></div></h2>
                    <h2 style="text-align: center;"><div id="nonazng">OnSite Non AZNG Emptys: <span id="val-nonazng" class="empty">0</span></div></h2>
                    <h2 style="text-align: center;"><div id="tractors">Tractors: <span id="val-tractors" class="empty">0</span></div></h2>
                    <h2 style="text-align: center;"><div id="nicarts">NICART Loads: <span id="val-nicarts" class="empty">0</span></div></h2>
                    <h2 style="text-align: center;"><div id="wro5bcn4div">${ymsConfig.searchRoute}: <span id="val-wro5bcn4" class="empty">0</span></div></h2>
                </div>
                `
            );

            updateTopBarVisibility(); // Inicjalne ukrycie elementów zgodnie z ustawieniami

            function emptyAZNG() {
                var tagged = 0, nicarts = 0, nonazng = 0, nonoff = 0;
                var tractorsYard = $(".yard-asset-icon-TRACTOR").length;
                var noTDR = $(".NoTDR").length;
                var psEmpty = $("tr.empty-location > td.col1 > div.location-type-ParkingLocation").length;
                var ddEmpty = $("tr.empty-location > td.col1 > div.location-type-ProcessingLocation").length;
                var emptyAZNGinPS = 0, emptyAZNGinDD = 0, empty3PinPS = 0, loadedAZNGnoVRID = 0;

                // Zliczanie specyficznych ładunków z dostrojonego wyszukiwania (Dynamic route)
                var dynamicRouteCount = $(`span[title='${ymsConfig.searchRoute}']`).length;

                $("tr.ng-scope").each(function () {
                    if ($(this).find(".location-type-ParkingLocation").length > 0 && $(this).find(".yardasset-empty").length > 0 && $(this).find('.ownerOperatorCodeGroup :contains("AZNG")').length > 0) emptyAZNGinPS++;
                    if ($(this).find(".location-type-ProcessingLocation").length > 0 && $(this).find(".yardasset-empty").length > 0 && $(this).find('.ownerOperatorCodeGroup :contains("AZNG")').length > 0) emptyAZNGinDD++;
                    if ($(this).find(".location-type-ParkingLocation").length > 0 && $(this).find(".yardasset-empty").length > 0 && $(this).find('.ownerOperatorCodeGroup :not(:contains("AZNG"))').length > 0) empty3PinPS++;
                    if ($(this).find(".yardAsset-unavailable").length > 0 && $(this).find('.ownerOperatorCodeGroup :contains("AZNG")').length > 0) tagged++;
                });

                var wholerows = document.querySelectorAll("tr.ng-scope");
                Array.prototype.forEach.call(wholerows, function (col) {
                    if (col.innerHTML.match(/highlight yardasset-full"/) && col.innerHTML.match(/AZNG/) && !col.innerHTML.match(/vrid/)) loadedAZNGnoVRID++;
                    else if (col.innerHTML.match(/highlight yardasset-empty"/) && !col.innerHTML.match(/TRACTOR highlight yardasset-empty"/) && !col.innerHTML.match(/AZNG/) && !col.innerHTML.match(/vrid/)) nonazng++;
                    else if (col.innerHTML.match(/highlight yardasset-empty"/) && !col.innerHTML.match(/AZNG/) && !col.innerHTML.match(/vrid/) && !col.innerHTML.match(/LDLB/) && !col.innerHTML.match(/BSPC/) && !col.innerHTML.match(/BRDZ/) && !col.innerHTML.match(/DUMMY/) && (!col.innerHTML.match(/class="col1 /) || col.innerHTML.match(/OSY/))) nonoff++;
                    if ((col.innerHTML.match(/TransfersEmptyCar/) || col.innerHTML.match(/NICARTS/i)) && !col.innerHTML.match(/yard-asset-icon-TRACTOR/)) nicarts++;
                });

                var tag = (psEmpty < 5) ? "emptyalert" : "empty";
                var tagtag = (tagged > 2) ? "emptyalert" : "empty";

                // Update DOM elements carefully to not overwrite parent structures
                document.getElementById("emptyazng").innerHTML = `AZNG Empties in PS: <span id="val-emptyazng" class="${tag}">${emptyAZNGinPS}</span>`;
                document.getElementById("taggedazng").innerHTML = `Tagged AZNG Trailers: <span id="val-taggedazng" class="${tagtag}">${tagged}</span>`;
                document.getElementById("dockempty").innerHTML = `AZNG Empties on DD: <span id="val-dockempty" class="empty">${emptyAZNGinDD}</span>`;
                document.getElementById("loadedAZNG").innerHTML = `Loaded AZNG w/ No VRID: <span id="val-loadedazng" class="empty">${loadedAZNGnoVRID}</span>`;
                document.getElementById("nicarts").innerHTML = `NICART Loads: <span id="val-nicarts" class="empty">${nicarts}</span>`;
                document.getElementById("tractors").innerHTML = `Tractors: <span id="val-tractors" class="empty">${tractorsYard}</span>`;
                document.getElementById("nonazng").innerHTML = `OnSite Non AZNG emptys: <span id="val-nonazng" class="empty">${empty3PinPS}</span>`;
                document.getElementById("psemptydiv").innerHTML = `Open Slips: <span id="val-psempty" class="empty">${psEmpty}</span>`;
                document.getElementById("ddemptydiv").innerHTML = `Open Dock Doors: <span id="val-ddempty" class="empty">${ddEmpty}</span>`;
                document.getElementById("tdrout").innerHTML = `Doors TDR'd Out: <span id="val-tdrout" class="empty">${noTDR}</span>`;

                // Zaktualizowana obsługa dynamicznej trasy wyszukiwania
                document.getElementById("wro5bcn4div").innerHTML = `${ymsConfig.searchRoute}: <span id="val-wro5bcn4" class="empty">${dynamicRouteCount}</span>`;
            }

            setInterval(emptyAZNG, 60000); 
            setTimeout(emptyAZNG, 10000); 
        }

        // ------------------------------------------------------------------------------------------------------------
        function addLicensePlateCopyButtons() {
            $("span[ng-if='yardAsset.vehicleNumber'], span[ng-if='yardAsset.licensePlateIdentifier && yardAsset.licensePlateIdentifier.registrationIdentifier']").each(function () {
                var numberHtml = $(this).html() || "";
                var number = numberHtml.split("<br>")[0].trim();

                if ($(this).parent().parent().find("button.oxy-copy-btn").length < 1) {
                    var copyButton = $("<button>", {
                        class: "oxy-copy-btn superuserTooltip",
                        title: "COPY TO CLIPBOARD",
                        text: "COPY",
                    }).click(function (e) {
                        e.preventDefault();
                        navigator.clipboard.writeText(number.split(" ")[0]).then(() => {
                            let ref = $(this);
                            ref.text("COPIED!");
                            setTimeout(function () { ref.text("COPY"); }, 2000);
                        });
                    });
                    $(this).parent().parent().append($("<br>")).append(copyButton);
                }
            });
        }

        function checkAndAddButtons() {
            if ($("#noteTextArea").is(":visible")) {
                if ($("#sealStatusDiv").length === 0 && typeof addSealStatusButtons === "function") addSealStatusButtons();
                if ($("#pageToggleButton").length === 0 && typeof createToggleButton === "function") createToggleButton();
                $("#pageToggleButton").show();

                if ($("#pageToggleButton").text() === "Next Page") {
                    $("#sealStatusDiv").show();
                    if ($("#page2Content").length > 0) $("#page2Content").hide();
                } else {
                    $("#sealStatusDiv").hide();
                    if ($("#page2Content").length === 0 && typeof createPage2 === "function") createPage2();
                    $("#page2Content").show();
                }
            } else {
                $("#sealStatusDiv, #page2Content, #pageToggleButton").hide();
            }
            addLicensePlateCopyButtons();

            // Detekcja i kolorowanie dynamicznie konfigurowanych tras (np. WRO5 -> BCN4)
            $(`span[title='${ymsConfig.searchRoute}']`).each(function () {
                if (!$(this).hasClass("dynamic-route-colored")) {
                    $(this).addClass("dynamic-route-colored");

                    // Stylizacja z pobraniem koloru z konfiguracji (ymsConfig.routeColor)
                    $(this).css({
                        "background-color": ymsConfig.routeColor,
                        "color": "#d50000", 
                        "font-weight": "bold",
                        "padding": "2px 5px",
                        "border-radius": "3px",
                        "border": "1px solid #d50000"
                    });

                    // Delikatny alpha kanał (20% opacności) dla podświetlenia tła
                    let hex = ymsConfig.routeColor.replace('#', '');
                    let r = parseInt(hex.substring(0, 2), 16), g = parseInt(hex.substring(2, 4), 16), b = parseInt(hex.substring(4, 6), 16);

                    $(this).closest("tr.ng-scope").css({
                        "box-shadow": `inset 0 0 0 2px ${ymsConfig.routeColor}`,
                        "background-color": `rgba(${r}, ${g}, ${b}, 0.15)`
                    });
                }
            });
        }

        setInterval(function () {
            checkAndAddButtons();
        }, 1500);

        // ------------------------------------------------------------------------------------------
        var isTopSectionVisible = true;
        var toggleButton;

        function toggleChanges() {
            var topbarData = document.getElementById("topbarData");
            var searchResults = document.querySelector(".ship-clerk-search-results");
            var tcpWidget = document.querySelector(".tcp-widget");
            var scrollTable = document.querySelector(".scrolltable");
            var topSection = document.getElementById("top-section");

            if (topbarData && searchResults && tcpWidget && scrollTable && topSection) {
                if (topbarData.style.visibility === "hidden") {
                    topbarData.style.visibility = "visible"; topbarData.style.opacity = "1"; topbarData.style.zIndex = "1";
                    toggleButton.innerHTML = "Collapse";
                } else {
                    topbarData.style.visibility = "hidden"; topbarData.style.opacity = "0"; topbarData.style.zIndex = "-999";
                    toggleButton.innerHTML = "Grow";
                }

                if (searchResults.style.marginTop === "-179px") {
                    searchResults.style.marginTop = "0"; searchResults.style.zIndex = "auto";
                } else {
                    searchResults.style.marginTop = "-179px"; searchResults.style.zIndex = "999";
                }

                tcpWidget.style.visibility = tcpWidget.style.visibility === "collapse" ? "visible" : "collapse";
                scrollTable.style.height = scrollTable.style.height === "150%" ? "100%" : "150%";

                if (isTopSectionVisible) {
                    topSection.style.display = "none"; isTopSectionVisible = false;
                } else {
                    topSection.style.display = "-webkit-flex"; isTopSectionVisible = true;
                }
            }
        }

        function addToggleButton() {
            var clearButtonGroup = document.getElementById("clearButtonGroup");
            if (clearButtonGroup) {
                clearButtonGroup.style.display = "flex";
                clearButtonGroup.style.justifyContent = "center";
                clearButtonGroup.style.alignItems = "center";
                toggleButton = document.createElement("button");
                toggleButton.innerHTML = "Collapse";
                toggleButton.style.cursor = "pointer";
                toggleButton.addEventListener("click", toggleChanges);
                clearButtonGroup.appendChild(toggleButton);
            }
        }
        setTimeout(addToggleButton, 5000);
    }
})(window, document);

